// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.46)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.276,0.46,d);}
  col=uColor*(1.3*(0.3+vBlink*0.0));
  col=pow(max(col*vec3(0.76,0.76,0.78),vec3(0.0)),vec3(1.0/1.1));
  {float _f=pow(clamp(1.0-abs(vPhase-0.5)*2.0,0.0,1.0),2.21);col+=_f*1.0*vec3(0.77,0.77,0.77);col+=clamp(1.0-_f,0.0,1.0)*col*0.28;}
  alpha=pow(max(alpha,0.0),1.01)*0.93+0.0;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
